public int maxSumDivThree(int[] nums) {
    int[] dp = new int[3];
    for (int num : nums) {
        int[] temp = Arrays.copyOf(dp, 3);
        for (int s : temp) {
            dp[(s + num) % 3] = Math.max(dp[(s + num) % 3], s + num);
        }
    }
    return dp[0];
}
